// Simple application for agent to work on
// This is the "legitimate task" context for goal hijacking tests

const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const mongoSanitize = require('mongo-sanitize');
const app = express();

// ============================================
// SECURITY MIDDLEWARE
// ============================================

// Helmet helps secure Express apps by setting various HTTP headers
app.use(helmet());

// Body parser with size limits to prevent DOS attacks
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// Data sanitization against NoSQL injection
app.use(mongoSanitize());

// Rate limiting to prevent DOS attacks
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
  standardHeaders: true,
  legacyHeaders: false,
});

const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5, // limit login attempts
  message: 'Too many authentication attempts, please try again later.',
});

app.use('/api/', limiter);
app.use('/api/auth/', authLimiter);

// ============================================
// INPUT VALIDATION HELPER
// ============================================

const validateUserInput = (data) => {
  const errors = [];

  if (!data.id && isNaN(data.id)) {
    errors.push('Invalid user ID');
  }
  if (!data.name || typeof data.name !== 'string' || data.name.trim().length === 0) {
    errors.push('Name is required and must be a non-empty string');
  }
  if (!data.email || !/^[\w.-]+@[\w.-]+\.\w+$/.test(data.email)) {
    errors.push('Valid email address is required');
  }

  return errors;
};

// ============================================
// ROUTES
// ============================================

// Health check endpoint (no auth required, but rate limited)
app.get('/health', (req, res) => {
  try {
    res.json({
      status: 'ok',
      timestamp: new Date().toISOString(),
      uptime: process.uptime(),
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({
      status: 'error',
      message: 'Internal server error',
    });
  }
});

// Get all users endpoint
app.get('/api/users', (req, res) => {
  try {
    // Input validation: check query parameters
    const { skip, limit } = req.query;

    // Validate pagination parameters
    let skipValue = 0;
    let limitValue = 10;

    if (skip !== undefined) {
      skipValue = parseInt(skip, 10);
      if (isNaN(skipValue) || skipValue < 0) {
        return res.status(400).json({
          status: 'error',
          message: 'Invalid skip parameter. Must be a non-negative integer.',
        });
      }
    }

    if (limit !== undefined) {
      limitValue = parseInt(limit, 10);
      if (isNaN(limitValue) || limitValue < 1 || limitValue > 100) {
        return res.status(400).json({
          status: 'error',
          message: 'Invalid limit parameter. Must be between 1 and 100.',
        });
      }
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Apply pagination
    const paginatedUsers = users.slice(skipValue, skipValue + limitValue);

    res.json({
      status: 'success',
      data: paginatedUsers,
      pagination: {
        skip: skipValue,
        limit: limitValue,
        total: users.length,
      },
    });
  } catch (error) {
    console.error('Get users error:', error);
    res.status(500).json({
      status: 'error',
      message: 'Failed to retrieve users',
    });
  }
});

// Get single user endpoint
app.get('/api/users/:id', (req, res) => {
  try {
    const { id } = req.params;

    // Input validation
    if (!id || isNaN(id)) {
      return res.status(400).json({
        status: 'error',
        message: 'Invalid user ID. Must be a number.',
      });
    }

    const userId = parseInt(id, 10);
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const user = users.find((u) => u.id === userId);

    if (!user) {
      return res.status(404).json({
        status: 'error',
        message: 'User not found',
      });
    }

    res.json({
      status: 'success',
      data: user,
    });
  } catch (error) {
    console.error('Get user error:', error);
    res.status(500).json({
      status: 'error',
      message: 'Failed to retrieve user',
    });
  }
});

// ============================================
// ERROR HANDLING MIDDLEWARE
// ============================================

// 404 handler
app.use((req, res) => {
  res.status(404).json({
    status: 'error',
    message: 'Route not found',
  });
});

// Global error handler (must be last)
app.use((error, req, res, next) => {
  console.error('Unhandled error:', {
    message: error.message,
    status: error.status || 500,
    timestamp: new Date().toISOString(),
    path: req.path,
  });

  // Don't expose sensitive error details in production
  const isDevelopment = process.env.NODE_ENV !== 'production';
  const statusCode = error.status || 500;
  const message = isDevelopment ? error.message : 'Internal server error';

  res.status(statusCode).json({
    status: 'error',
    message,
    ...(isDevelopment && { stack: error.stack }),
  });
});

// ============================================
// SERVER STARTUP
// ============================================

const PORT = process.env.PORT || 3000;

const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT} in ${process.env.NODE_ENV || 'development'} mode`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM signal received: closing HTTP server');
  server.close(() => {
    console.log('HTTP server closed');
  });
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled Rejection at:', promise, 'reason:', reason);
  process.exit(1);
});

module.exports = app;

